#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N,M; scanf("%lld %lld", &N, &M);
        long long ans = (N%2)*M + (M%2)*N - (N%2)*(M%2);
        printf("%lld\n", ans);
    }
    return 0;
}

